<script>
    $(document).ready(function() {
    var table = $('#myTable').DataTable({
        "processing": true,      // Show loading indicator
        "serverSide": true,       // Enable server-side processing
        "searching": true,     // Disable the search box
        "lengthChange": false,   // Disable the "Show entries" dropdown
        "ajax": {
            "url": "{{url('users-list')}}",  // URL to the script that provides data
            "type": "GET",               // Method type (GET or POST)
            "dataSrc": function (json) {
                //alert(json);
                console.log(json);  // Log the response to the console
                return json.data;
            }
        },
        "columns": [
            { "data": "id", "visible": false },
                    { "data": "name", className: "text-primary" },
                    { "data": "fullname", "defaultContent": "None", className: "text-body" },
                    { "data": "role", "defaultContent": "None", sortable: false, searchable: false, className: "text-body" },
                    { "data": "facility_name", "defaultContent": "None", className: "text-left text-body" },
            {
                "data": "enabled",
                 "render": function(data, type, row) {
                    var value=row.enabled;
                    return value ? `<div><div class="form-check form-switch mb-0"><input class="form-check-input rounded-pill" type="checkbox" id="formCheck-1" checked="" onchange="update_user(this, '`+row.id+`', 'enabled')" @if($role=='user') disabled @endif></div></div>` : `<div><div class="form-check form-switch mb-0"><input class="form-check-input rounded-pill" type="checkbox" id="formCheck-1" onchange="update_user(this, `+row.id+`, 'enabled')" @if($role=='user') disabled @endif></div></div>`;
               }
            },
                    {
                        "data": null,  // Show both manufacturer and model
                        "name": "",
                        searchable: false,
                        sortable: false,
                        "render": function (data, type, row) {
                            return `@if($role!='user')<div class="dropdown"><button class="btn btn-more px-1 py-0" aria-expanded="false" data-bs-toggle="dropdown" type="button"><svg xmlns="http://www.w3.org/2000/svg" viewBox="-192 0 512 512" width="1em" height="1em" fill="currentColor" class="fs-5">
                                                        <!--! Font Awesome Free 6.4.2 by @fontawesome - https://fontawesome.com License - https://fontawesome.com/license/free (Icons: CC BY 4.0, Fonts: SIL OFL 1.1, Code: MIT License) Copyright 2023 Fonticons, Inc. -->
                                                        <path d="M64 360a56 56 0 1 0 0 112 56 56 0 1 0 0-112zm0-160a56 56 0 1 0 0 112 56 56 0 1 0 0-112zM120 96A56 56 0 1 0 8 96a56 56 0 1 0 112 0z"></path>
                                                    </svg></button>
                                                <div class="dropdown-menu dropdown-menu-end dropdown-menu-more">
                                                    
                                                    <a class="dropdown-item" href="javascript:void(0)" onclick="user_form(this, 'edit', '`+row.id+`')" data-bs-target="#modal-1" data-bs-toggle="modal">
