     function user_form(th, action, id='0')
    {
        var formData=new FormData();
        formData.append('_token', '{{csrf_token()}}');
        formData.append('id', id);
        
         $.ajax({
            url: "{{url('user-form')}}",
            type: "POST",
            data:  formData,
            beforeSend: function(){ //alert('sending');
            },
            contentType: false,
            processData:false,
            success: function(data) { //alert(data);
                if ( ! data.success) {
                } else {
                    // ALL GOOD! just show the success message!
                    $("#user_form_box").empty();
                    $("#user_form_box").append(data.content);
                }
            },
            error: function()  {
                //error
            } 	        
        });
    }
    
    window.delete_id=0;
    function delete_record(th, id)
    {
        $("#modal-delete").modal('show');
        window.delete_id=id;
    }

    function confirm_delete(th)
    {
        var formData=new FormData();
        formData.append('_token', '{{csrf_token()}}');
        formData.append('id', window.delete_id);
                
        $.ajax({
            url: "<?php echo url('delete-user') ?>",
            type: "POST",
            data:  formData,
            beforeSend: function(){ //alert('sending');
                $(th).attr('disabled', true);
            },
            contentType: false,
            processData:false,
            success: function(data) { //alert(data);
                //success
                // here we will handle errors and validation messages
                $(th).attr('disabled', false);
                if ( ! data.success) {
                    notify('failed', data.msg);
                } else {
                    // ALL GOOD! just show the success message!
                    //$("#record-"+window.delete_id).remove();
                    window.table.draw();
                    $("#modal-delete").modal('hide');
                    notify('success', data.msg);
                }
            },
            error: function()  {
                //error
            } 	        
        });
    }
</script>